import user from '../data/user.json';
import statisticalData from '../data/statisticalData.json';
import friends from '../data/friends.json';
import transaction from '../data/transaction.json';

import './App.css';
import React from 'react';
import Profile from './profile/Profile';
import Statistic from './statistic/Statistic';
import Friends from './friendList/Friends';
import TransactionHistori from './transactionHistori/TransactionHistori';




const App = () => {
     return (
          <>
               <Profile user={user}/>
               <Statistic statisticalData={statisticalData} title='Upload stats'/>
               <Friends friends={friends}/>
               <TransactionHistori transaction={transaction} />
          </>
     );
};

export default App;