import React from "react";
import TransactionItem from "./TransactionItem";
import PropTypes from 'prop-types';

const TransactionHistori = ({transaction}) => {
  return (
    <table className="transaction-history">
      <thead>
        <tr>
          <th>Type</th>
          <th>Amount</th>
          <th>Currency</th>
        </tr>
      </thead>

      <tbody>
          {transaction.map(data=><TransactionItem key={data.id} type={data.type} amount={data.amount} currency={data.currency} />)}
      </tbody>
    </table>
  );
};

export default TransactionHistori;

TransactionHistori.propTypes = {
  transaction: PropTypes.array.isRequired,
};


